module RefModule(
    input Clk,ShiftIn,load,ShiftEn,
    input [3:0] ParallelIn,
    output ShiftOut, 
    output [3:0] RegContent
    );reg [3:0] unused_shift_reg;
    always @(posedge Clk)
        if(load)
            unused_shift_reg <= ParallelIn;
        else if (ShiftEn)
            unused_shift_reg <= {unused_shift_reg[2:0], ShiftIn};
    assign ShiftOut = unused_shift_reg[3];
    assign RegContent = unused_shift_reg;
endmodule
